INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989551","title":"Бен Рейли. Алый паук","author":"Питер Дэвид","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005381319/140/718a/Piter_Devid__Ben_Rejli._Alyj_pauk.jpg","isbn":"978-5-04-110547-1","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Один из самых противоречивых персонажей в истории комиксов возвращается! Вы все помните Бена Рейли – клона Человека-Паука, созданного Шакалом и вернувшегося, чтобы перевернуть жизнь Питера Паркера с ног на голову! Когда-то Бен стал Алым Пауком и даже ненадолго перенял титул Человека-Паука у Питера, но вскоре умер смертью героя. И вот, в результате событий \"Заговора клонов\" Бен Рейли возвращается в строй! Но он уже не тот Алый Паук, что раньше. Конечно, схожесть очевидна, вот только он стал гораздо злее, переехал в Лас-Вегас и собирается начать новую жизнь. Многие идут по его душу, но страшнее всех другой клон Питера, Каин – ещё один Алый Паук, всерьёз решивший прикончить Бена! Старые друзья и новые враги, сделки с дьяволом и поцелуи со смертью, злобные динозавры и проклятые Мстители – в Вегасе скучать не приходится, но переживёт ли Рейли такое веселье? В книгу входят комиксы \"Бен Рейли: Алый Паук\" #1–25 и \"Метатели\" #0. В сборник вошёл весь онгоинг 2017-2018 года, а также ван-шот Заговор Клонов: Омега и Метатели #0 (1998).Перед прочтением стоит ознакомиться с онгоингом Человека-Паука (Amazing Spider-Man vol. 4), а также с событием лежащим в самом онгоинге – Заговором Клонов (Clone Conspiracy #1-5). Но они не обязательны, так как в начале сборника есть предисловие о ключевых событиях. Само же чтение Заговора Клонов поможет для понимания первой арки Рейли. Мне, например, было совсем неожиданно увидеть, что первая арка фактически является последствием Заговора Клонов.Ван-шот даёт толчок онгоингу, рассказывая об удачных обстоятельствах на трудном жизненном пути Бена Рейли: он спасается и переезжает в Лас-Вегас. В новом городе Рейли разживается и новым костюмом (чуть позже костюм вновь поменяется и станет прежним. Редактура Марвел вышла из чата. К тому же, на каждой из обложек первой арки (#1-3) был изображён старый костюм, скорее всего редактор – Ник Лоу (довольно значимый человек в Marvel) просто забил на такую несостыковку после того, как Марк Багли нарисовал эскиз нового костюма).Над всем онгоингом работал один сценарист – Питер Дэвид. На протяжении комикса героев преследуют двойные стандарты, они никогда не доделывают дела до конца и постоянно перебегают от одного утверждения к другому. Также могу заметить множество открытых сюжетных поворотов, которые остались обделёнными, что очень странно, ведь они были неплохими. Без присутствуя кучи сюжетных дыр не обошлась и в этот раз. Из-за всех, наверняка редакторских ошибок, качество комикса страдает, из неплохой завязки первой арки (которая также обладает двойственностью поступков) читатель получает довольно странное чтиво на пару вечеров. Отмечу плюс комикса: его интересно читать, даже несмотря на спорное качество сюжета.Каждая арка обладает чем-то интересным и абсурдным. Могу выделить первую – она наиболее проработана и детальна, даже исходя и из рисунка Марка Багли. Рука художника уже давно не та, что была раньше, но арт вышел неплохим. Сам онгоинг проходит через три события: Заговор Клонов, Секретная Империя, Проклятие (Доктор Стрэндж).Следующим художником, рисовавшим большую часть комикса выступит Уилл Слайни. Хороший, стандартный, современный арт Марвел. Иногда интересная работа с деталями, а на другой странице арт попахивает халтурой. Следующим художником на пару номеров выступил Андрэ Лима Араухо – его арт спорный, весьма странная и гипертрофированная передача деталей. Бруно Оливьера – художник, рисовавший два последних номера. Арт очень блеклый и халтурный по сравнению с его предшественниками.Огромная претензия к комиксу – это редакторская работа, которую на самом деле очень плохо видно, а также сумасшедший и трешовый сюжет арок. Питер Дэвид явно не показательный автор в нынешнее время. Задумка была грандиозная, ведь в комиксе приняли участие очень много именитых геров и злодеев, а также божественных существ, но как воплотить это в действительность, не растеряв при этом смысл сущего, простого и истинно людского, ведь комикс о Человеке-Пауке – неизвестно. Еженедельная рубрика о прочитанном в группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":3,"review":"","added":9999697,"hdCover":""},{"id":"0989550","title":"Spider-Woman: Origin","author":"Брайан Майкл Бендис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193857/140/e6a7/Brajan_Majkl_Bendis__SpiderWoman_Origin.jpg","isbn":"978-0785119661","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"This all-new epic chronicles the intriguing secret history of Jessica Drew and her journey from child experiment to Hydra agent to S.H.I.E.L.D. agent to super hero to private eye to Avenger! Written by New Avengers scribe Brian Michael Bendis and searing-hot newcomer Brian Reed (Ms. Marvel), and featuring stunning full-color visuals by the Luna brothers (Ultra, Girls), this story is packed with intrigue leading directly into the upcoming Spider-Woman series from Bendis and Eisner Award-winning artist Alex Maleev (Daredevil).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-08","rating":2,"review":"","added":9999696,"hdCover":""},{"id":"098954f","title":"Серджио Арагонес разносит MARVEL","author":"Марк Эваньер,Серджио Арагонес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003873285/140/ac82/__Serdzhio_Aragones_raznosit_MARVEL.jpg","isbn":"978-5-04-110020-9","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Marvel. Альтернатива","genres":["Комиксы","манга","графические романы"],"annotation":"Великий художник комиксов Серджио Арагонес проникает в издательство \"Марвел\", чтобы предложить свои услуги, но никого там не обнаруживает. Что же он делает? Решает за один день нарисовать ВСЕ КОМИКСЫ МАРВЕЛ, дабы показать свои силы, пока есть возможность. Вот все поразятся, когда вернутся! В результате он попутно высмеивает ВСЕ КОМИКСЫ МАРВЕЛ, а заодно и саму индустрию комиксов, франшизы, страсть к коммерции и даже самого себя. Количество пасхалок превышает все разумные пределы, а юмор заставляет неистово хвататься от смеха за живот на протяжении всего комикса!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":3,"review":"","added":9999695,"hdCover":""},{"id":"098954e","title":"Astonishing Tales: Spider-Woman","author":"Джонатан Грин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006245673/140/5213/Dzhonatan_Grin__Astonishing_Tales_SpiderWoman.jpg","isbn":"","publisher":"Marvel","pubDate":"2009","language":"","series":"","genres":[],"annotation":"MARVEL DIGITAL COMICS EXCLUSIVE Before Secret Invasion, before Dark Reign, Jessica Drew was a P.I. desperate to survive in Los Angeles. Writer Jonathan Green (Anita Blake: The First Death) and the incredible Fiona Staples give us an untold tale of Spider-Woman''s past...and some of Hollywood''s most horrible vampires!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":2.5,"review":"","added":9999694,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098954d","title":"Супергерои Marvel. Официальная коллекция №47. Женщина - Паук","author":"Арчи Гудвин,Брайан Бендис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006244449/140/26ed/__Supergeroi_Marvel._Ofitsialnaya_kollektsiya_No47._Zhenschina__Pauk.jpg","isbn":"9772619134308","publisher":"Hachette Marvel","pubDate":"2020","language":"","series":"Супергерои Marvel. Официальная коллекция","genres":[],"annotation":"Женщина - Паук вселяет во врагов страх... Мы предлагаем вам убедиться в этом и узнать самые мрачные тайны героини, которая слишком долго была во власти зла. Чтобы совладать с травмами прошлого, Джессика отправляется на новое задание и становится защитницей человечества от самых опасных затаившихся врагов - армии скруллов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4,"review":"","added":9999693,"hdCover":""},{"id":"098954c","title":"Spider-Woman Saga","author":"Джон Ретт Томас,Джесс Гарольд","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006244356/140/eee6/__SpiderWoman_Saga.jpg","isbn":"","publisher":"Marvel","pubDate":"2006","language":"","series":"","genres":[],"annotation":"The explosive Eisner award-winning team of Bendis and Maleev reunite for their first ongoing series since Daredevil! Ripped from the pages of New Avengers and Secret Invasion, watch as the gorgeous and mysterious Jessica Drew reenters a society she did not make...as an AGENT OF S.W.O.R.D. Now, get a look at Spider-Woman secret history in this exclusive Marvel Digital Comic!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":3,"review":"","added":9999692,"hdCover":""},{"id":"098954b","title":"Giant-Size Spider-Woman","author":"Крис Клэрмонт,Арчи Гудвин,Брайан Бендис,Марк Вульфман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006244341/140/35dd/__GiantSize_SpiderWoman.jpg","isbn":"","publisher":"Marvel","pubDate":"2005","language":"","series":"","genres":[],"annotation":"To know her is to fear her! In celebration of the original Spider-Woman’s triumphant return in the pages of NEW AVENGERS comes this colossal collection of classic tales – plus a brand-new 8-page story by NEW AVENGERS scribe BRIAN MICHAEL BENDIS and artist RICK MAYS (ULTIMATE MARVEL TEAM-UP)!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":2.5,"review":"","added":9999691,"hdCover":""},{"id":"098954a","title":"Воспоминания Эманон","author":"Синдзи Кадзио,Кэндзи Цурута","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005615085/140/0ba5/__Vospominaniya_Emanon.jpg","isbn":"978-5-905295-72-0","publisher":"Alt Graph","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"1967 год. Америка отправила полмиллиона солдат на войну во Вьетнаме, тестовый запуск «Аполлона-1» обернулся первыми в истории космонавтики жертвами. На киноэкранах Джеймс Бонд сражался с преступной организацией СПЕКТР, «Битлз» записывала альбом Sgt. Pepper''s Lonely Hearts Club Band. А молодой японский студент, который обожает научную фантастику и которому в очередной раз разбили сердце, возвращается на ночном пароме домой. Здесь он встречает загадочную девушку по имени Эманон и немедленно в неё влюбляется. Они болтают ночь напролёт обо всём подряд: о поп-музыке и джазе, о фильмах и теории литературы, о путешествиях автостопом и бейсболе. Эманон делится с ним секретом, о котором не знает ни единая душа на планете, а на утро исчезает без следа.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":5,"review":"","added":9999690,"hdCover":""},{"id":"0989549","title":"Палео: Истории позднего мелового периода. Выпуск 3","author":"Джим Лоусон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001397437/140/8e33/Dzhim_Louson__Paleo_Istorii_pozdnego_melovogo_perioda._Vypusk_3.jpg","isbn":"978-5-9906218-3-1","publisher":"Illusion Studios","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Красивый, ясный день. Малыш стегоцера чувствует себя превосходно: целый мир открыт его детскому взору, а заботливая мать защитит от любой напасти. Но яркое солнце, дарующее тепло доисторическому миру, на секунду меркнет, когда в небе появляется кетцалькоатль - его появление подобно первобытному ангелу смерти, и оно уж точно не сулит ничего хорошего... Почувствуйте великолепие доисторического мира во всех его красках!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4,"review":"","added":9999689,"hdCover":""},{"id":"0989548","title":"Палео: Истории позднего мелового периода. Выпуск 2","author":"Джим Лоусон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001326217/140/8dff/Dzhim_Louson__Paleo_Istorii_pozdnego_melovogo_perioda._Vypusk_2.jpg","isbn":"978-5-9906218-2-4","publisher":"Illusion Studios","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Каково быть отщепенцем в стае хищных дромеозавров? Оставаться в тени своих сородичей, доедать объедки и получать нагоняи от вожака? Возможно, с положением в стае нужно просто смириться... Но беспокойное молодое сердце хищника не даёт покоя - а значит настанет тот день, и некогда склонивший голову поднимется на ноги и кинет гордый победный клич. Почувствуйте великолепие доисторического мира во всех его красках!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4,"review":"","added":9999688,"hdCover":""},{"id":"0989547","title":"Палео: Истории позднего мелового периода. Выпуск 1","author":"Джим Лоусон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001291598/140/ac42/Dzhim_Louson__Paleo_Istorii_pozdnego_melovogo_perioda._Vypusk_1.jpg","isbn":"978-5-9906218-1-7","publisher":"Illusion Studios","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Первая история позднего мелового периода познакомит читателя с отважной самкой трицератопса, которой предстоит пройти через нелегкие испытания: в одиночку столкнуться с большими хищниками, совладать со своим страхом и преодолеть таинственные опасности, которые хранят дремучие хвойные леса. Почувствуйте все великолепие доисторического мира во всех его красках!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4,"review":"","added":9999687,"hdCover":""},{"id":"0989546","title":"Черепаховый Суп. Полное издание","author":"Кевин Истмен,Джим Лоусон,Питер Алан Лерд","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006241485/140/db3b/__Cherepahovyj_Sup._Polnoe_izdanie.jpg","isbn":"978-5-9909197-2-3","publisher":"Illusion Studios","pubDate":"2016","language":"","series":"","genres":[],"annotation":"Перед вами самый полный сборник каноничных коротких историй комиксов о классических Черепашках-Ниндзя, опубликованных в период с 1986-го по 1992 годы во всевозможных дополнительных тиражах, переизданиях и спецвыпусках как в черно-белом виде, так и в цвете. Больше 40 историй настоящей Черепашьей Силы под одной обложкой!  Авторами историй выступают легендарные создатели Черепашек-Ниндзя Кевин Истмен и Питер Лерд, их верные соратники из \"Mirage Studios\" Стив Лавин, Джим Лоусон, Райан Браун, Дэн Бергер, Эй Си Фарли, а также приглашенные друзья-художники, широко известные в узких кругах американских андеграунд-комиксов конца 80-ых: Ричард Корбен, Майкл Зулли, Рик Артур, Рик МакКолюм, Майкл Гайдос, Джефф Бониверт и другие!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4,"review":"","added":9999686,"hdCover":""},{"id":"0989545","title":"Marvel''s Jessica Jones #1","author":"Майкл Гэйдос,Брайан Майкл Бендис,Дэвид Мак","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001488718/140/a07e/__Marvel039s_Jessica_Jones_1.jpg","isbn":"B015QL71YA","publisher":"Marvel","pubDate":"2015","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":3,"review":"","added":9999685,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
