FROM json_each('[{"id":"0989544","title":"Секретная война","author":"Брайан Майкл Бендис,Габриель Делль’Отто","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000461750/140/58f6/__Sekretnaya_vojna.jpg","isbn":"978-5-414-00213-0","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Золотая коллекция комиксов","genres":["Комиксы","манга","графические романы"],"annotation":"Человек-Паук, Росомаха, Капитан Америка, Железный Кулак, Дардевил... Величайшие герои Marvel вышли из-под контроля! Они нарушили запрет правительства, нарушили нормы ООН. Герои тайно пересекли границу и развязали войну на территории Латверии - мирного государства, которым больше не правит диктатор Доктор Дум. Может быть, супергерои мстят? Или они преследуют личные цели? И кто же руководит слаженными действиями их команды? В этой книге вы узнаете имя главного виновника Секретной Войны, которая поставила под угрозу уничтожения весь мир. Этим человеком может оказаться... прославленный супергерой!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":3.5,"review":"","added":9999684,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
