  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989543","title":"Джессика Джонс. Пульс. Полное издание","author":"Брайан Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006077571/140/b484/Brajan_Bendis__Dzhessika_Dzhons._Puls._Polnoe_izdanie.jpg","isbn":"978-5-04-117346-3","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Джессика Джонс, звезда хита Брайана Майкла Бендиса \"Элиас\", возвращается! Бывшая Мстительница, ставшая частным детективом, начала очередную главу своей жизни: теперь она работает в \"Пульсе\" — новой рубрике \"Дэйли Бьюгл\" про супергероев. Первое задание: раскрыть личность сверхсильного убийцы репортёрши \"Бьюгл\"! Как с этим связан Норман Озборн? И как шокирующее открытие Джессики повлияет на всю вселенную Marvel? Поиск ответов только усложнился, когда Тайная война Ника Фьюри захлестнула улицы города — и настигла Джессику и Люка Кейджа прямо у них дома! Их жизни разрушены, но Джессика решила дать отпор! И наконец то, чего вы так ждали: рождение ребёнка Джессики и Люка, а также их свадьба! При участии Человека-паука, Капитана Америка, Новых Мстителей и не только!  В сборник вошли выпуски комикса \"Пульс\" #1–9 и #11–14, а также \"Новые Мстители. Ежегодник\" #1 (2006) сценариста Брайана Майкла Бендиса и художников Марка Багли, Брента Андерсона, Майкла Ларка, Майкла Гэйдоса и Оливье Куапеля.  \"Сорвиголова\", \"Джессика Джонс. Элиас\", \"Тайная война\", \"Новые Мстители\". Все эти комиксы отставили свой след в сердцах настоящих фанатов графических романов. А ещё их сюжеты тесно вплетены Брайаном Майклом Бендисом в повествование \"Пульса\"! Джессика Джонс и Бен Урих увидят последствия событий, описанных в самых значимых работах легендарного сценариста. Также найдётся место реверансам авторам прошлого, таким как Фрэнк Миллер и Курт Бьюсик. Но главное, кончено же, сама история \"Пульса\" — читателя ждёт увлекательнейшая процедурная драма о работе журналистов и непростой семейной жизни супергероев. Перед прочтением данного сборника об уже известной героини Marvel стоит ознакомиться с предшествующем событиям Пульс онгоингом «Джессика Джонс. Элиас» Брайана Бендиса и Майкла Гэйдоса. Комикс мне очень понравился, есть очень сильные по сюжету и поворотам арки, например, первый том (#1-9) я читал взахлёб, не мог остановиться из-за потрясающей завязке, клиффхэнгерах и невероятных диалогах. Раскадровка потрясающая, очень чётко переданы эмоции персонажей даже при помощи многочисленного повторения одного и того же кадра. В общем, комикс оставил только положительные впечатления, рекомендую ознакомиться всем фанатам сценариста, Сорвиголовы и Джессики Джонс.Но на этом история жизни Джонс не заканчивается. Элиас оставляет за собой хороший клиффхэнгер, который будет являться одним из сюжетных линий в комиксе «Джессика Джонс. Пульс» от Бендиса и различных художников. Всего в комиксе 14 номеров, в сборник не включён лишь #10 (номер является тай-ином к Дню М, проходной для общего сюжета комикса, но ознакомиться стоит при прочтении события). Также в сборник от Комильфо вошёл Annual #1 The New Avengers. А теперь чуть подробнее про сюжет и мои эмоции. Первая арка (#1-5) раскрывает новые подробности взаимоотношений между Джессикой Джонс и Дэйли Бьюгл (Джей Джона Джеймсон, Робби Уильямс, Бен Урих, Кэт Фаррелл). Джессику приглашают на работу для ведения колонки про супергероев под названием «Пульс». Арка интересна своим детективным начинанием, в ходе которого герои пытаются понять, кто совершил убийство одного из работников газеты. Хорошая история для начала комикса, читать было интересно. Художником выступил Марк Багли, арт хороший, конечно не Современный Человек-Паук, но типу истории соответствует. Раскадровка (скорее всего Бендис руководит производством страниц) отличная.Вторая арка (#6-9) является неким тай-ином к Секретной Войне, чтение которой мне только предстоит. Загадочная фигура проникает в квартиру Джессики и Люка, взрываясь. Люк попадает в больницу, а сюжет начинает закручиваться, появляются новые загадки: что произошло? кто это был? почему Ник Фьюри причастен к случившемуся? На эти вопросы в большем объёме должно ответить само событие. Арка понравилась ещё больше, чем предыдущая. Живые и затрагивающие до мурашек диалоги, а также нестандартный подход к раскрытию знакомых, но поверьте, вы их не знаете так, как знает Бендиса, персонажей. Вновь оглашу (весь комикс такой) – великолепная раскадровка, например, арт находится слева/ справа, а в другой стороне расположен текст в виде пьесы. Художником выступили: Брент Андерсон (#6-7) и Майкл Ларк (#8-9). Оба художника неплохо выполняли свою работу, арт приятен. Особенно интересна работа с цветом Пита Пантазиса, в духе Мэтта Холлингсворта, который будет чуть позже.Третья арка (#11-14) расскажет читателю о подготовке Джессики к родам. Она встречается с другими супергероинями, обсуждая насущное. Попутно сюжетной линии Джессики нам показывают новое расследование Бена Уриха, который натыкается на странные события с ограблением ювелирных магазинов. Я считаю, что сам сюжет с раскрытием безызвестного супергероя Ди Мена – это дань уважения Бендиса Сорвиголове. Бен Урих пытается понять главные мотивы героя, его историю и узнать о жизненных этапах. Моя любимая цитата из всего комикса (поверьте, их было немало, так как Бендис мастерски обыгрывает словесные перепалки между героями): «Люди могут дополнять ярлыки… Падший герой. «Падший герой». Но всё равно «герой». Герой. Это слово как огромный занавес… и мы многое позволяем скрывать за ним. В большинстве случаев, если на тебя повесить ярлык, он остаётся с тобой… Но что делать с человеком под ярлыком? Что делать с человеком, скрывающимся под маской, которому просто нужна наша помощь? Всего лишь помощь, друзья и любовь. Как и всем остальным.» Из статьи в газете Дэйли Бьюгл. Очень сильная и трогательная до глубины души история. Позже в ней появляется Сорвиголова, только из-за одного факта я мог бы поставить комиксу наилучшую оценку, но и её он непременно заслуживает. Тем временем Джессика рожает девочку, а Люк делает предложение руки и сердца. Позже Джессика дискутирует об этом с дочкой и принимает решение, что согласна выйти замуж. Художником выступил Майкл Гэйдос, его арт мне нравится, но явно не для всех. Статичные детали и странные контуры. Поздний Гэйдос напоминает уже Малеева, поэтому оба художника мне по душе. Но как же Гэйдос обойдётся без Холлингсворта? Поэтому Мэтт специально вернулся в комиксы, чтобы поработать над аркой (что можно узнать из интервью Бендиса). Люблю хорошо прописанных персонажей, Бендис справляется великолепно.Даже ежегодник вышел не блеклым отражением чего-то. Это вполне самобытная история, приоткрывающая детали спецоперации Мстителей на Дикой Земле. Даже обычное клише отлично смотрится в виде совместного противостояния команды врагу. Наоборот, именно ежегодник показывает всю целостность и эпичность созданной Бендисом империи супергероев. На брачной церемонии священником оказывается Стэн Ли, прекрасная отсылка! Номер заканчивается признанием Джессики в любви Люку и страстным поцелуем молодожён.Из интервью можно выделить пару интересных фактов. Например, что серию после ухода Бендиса должен был писать Пол Дженкинс, но его поставили сценаристом на тай-ин к Гражданской Войне «На передовой». Послесловие трогательное, в принципе, как и все послесловия автора. Еженедельная рубрика о прочитанном в группе ВК                                                Свернуть","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4.5,"review":"","added":9999683,"hdCover":""}]');

