  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989542","title":"Мотористка. Омнибус","author":"Терри Мур","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006222885/140/1e01/Terri_Mur__Motoristka._Omnibus.jpg","isbn":"9785950067082","publisher":"Рамона","pubDate":"2021","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Саманта – ветеран Иракской войны. Она ведёт весьма непримечательную жизнь: работает на свалке, чинит автомобили и... постоянно спорит с огромной говорящей гориллой. Но однажды случается невероятное! На их мастерскую падает НЛО, и быт героев переворачивается с ног на голову. Сэм и её грозный друг Майк всегда готовы встать на защиту слабых, даже если те прилетели из далёкого космоса и говорят на неизвестном языке. Но, возможно, нашей героине тоже нужна помощь? «Мотористка» – очень трогательный комикс, тепло воспринятый критиками. Он непременно рассмешит и удивит любого читателя.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4.5,"review":"","added":9999682,"hdCover":""},{"id":"0989541","title":"Шараз-де","author":"Серджо Топпи","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001252942/140/f2dc/Serdzho_Toppi__Sharazde.jpg","isbn":"978-5-904662-17-2","publisher":"Zangavar","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Шараз-де» — это собрание уникальных графических новелл, созданных по мотивам цикла «Тысячи и одной ночи». Переосмысленное видение знаменитого литературного памятника средневекового Востока принадлежит авторству итальянца Серджо Топпи. Одиннадцать сказок, поведанных девушкой по имени Шараз-де (в ней вы без труда узнаете Шахразаду), которая спасала себе жизнь, избегая участи, уготованной ей царём Шах-Рияром, составили этот шедевр изумляющего изобразительного мастерства Топпи — «Гюстава Доре ХХ века». Благодаря самобытной манере рисунка, до сих пор непревзойдённого по уровню гравюрной детализации, художник вырывается за пределы традиционного комикса. Деформации перспективы, парадоксальные композиционные решения, нестандартные макетные ходы — всё это накладывается на сюжетные повороты захватывающих историй о предательстве, страхе, сострадании, мести, о человеческих пороках и справедливости Высшей силы, о неизбежности возмездия за совершённые преступления.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":4.5,"review":"","added":9999681,"hdCover":""},{"id":"0989540","title":"Лунный Рыцарь. Том 3. Ночь","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002079184/140/3411/Kallen_Bann__Lunnyj_Rytsar._Tom_3._Noch.jpg","isbn":"","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Наступает ночь. Засыпают мирные жители, просыпается самый странный герой Marvel, защитник ночных странников, великолепный и безумный Лунный Рыцарь. На этот раз его ждет противостояние с профессиональными ловцами душ, детскими кошмарами, культистами и не только... но, как всегда у Лунного Рыцаря, самый страшный противник - он сам.  По традиции, в третьей книге также сменился коллектив авторов: на этот раз сценаристом стал Каллен Банн (многие его знают по комиксам о Дэдпуле, но в данном случае гораздо важнее его работа над прекрасным хоррором \"Округ Хэрроу\"), а художниками - Рон Акинс и Герман Перальта.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-07","rating":3,"review":"","added":9999680,"hdCover":""}]');

